import React, { useState } from 'react';
import axios from 'axios';
import { Upload, Loader2, CheckCircle } from 'lucide-react';

const CLOUD_NAME = "dwpgncjgn";
const UPLOAD_PRESET = "productos"; // <-- Coloca aquí el nombre de tu preset Unsigned
const API_URL = "http://localhost:5000";

const SubirImagenes = ({ onFinished }) => {
    const [loading, setLoading] = useState(false);

    const handleUpload = async (e) => {
        const files = Array.from(e.target.files);
        if (files.length === 0) return;
        
        setLoading(true);
        try {
            for (const file of files) {
                const formData = new FormData();
                formData.append('file', file);
                formData.append('upload_preset', UPLOAD_PRESET);

                // Subida directa a Cloudinary
                const res = await axios.post(
                    `https://api.cloudinary.com/v1_1/${CLOUD_NAME}/image/upload`,
                    formData
                );

                // Guardamos en tu base de datos
                // res.data.public_id ahora será exactamente el nombre del archivo
                await axios.post(`${API_URL}/api/galeria`, {
                    nombreReferencia: res.data.public_id.replace(/_/g, ' '), 
                    publicId: res.data.public_id,
                    url: res.data.secure_url,
                    formato: res.data.format
                });
            }
            alert("¡Imágenes cargadas y vinculadas con éxito!");
            if (onFinished) onFinished();
        } catch (err) {
            console.error("Error en la subida:", err);
            alert("Hubo un error al subir. Revisa el preset.");
        } finally {
            setLoading(false);
            e.target.value = null;
        }
    };

    return (
        <label style={btnStyle}>
            {loading ? <Loader2 className="animate-spin" size={18} /> : <Upload size={18} />}
            {loading ? "Procesando..." : "Cargar Imágenes"}
            <input type="file" multiple onChange={handleUpload} hidden accept="image/*" />
        </label>
    );
};

const btnStyle = {
    background: '#3b82f6', color: 'white', padding: '10px 20px',
    borderRadius: '12px', fontWeight: 'bold', display: 'flex',
    alignItems: 'center', gap: '8px', cursor: 'pointer', border: 'none'
};

export default SubirImagenes;
